282	async function runPiOnThread(
283		cwd: string,
284		sessionPath: string,
285		message: string,
286		model: string | undefined,
287		systemPromptFile: string | undefined,
288		signal: AbortSignal | undefined,
289		onMessage?: (msg: Message) => void,
290	): Promise<{ exitCode: number; messages: Message[]; stderr: string }> {
291		const args: string[] = ["--mode", "json", "-p", "--no-extensions", "--no-skills", "--no-prompt-templates"];
292		args.push("--session", sessionPath);
293		if (model) args.push("--model", model);
294		if (systemPromptFile) args.push("--append-system-prompt", systemPromptFile);
295		args.push(message);
296	
297		const messages: Message[] = [];
298		let stderr = "";
299		let wasAborted = false;
300	
301		const exitCode = await new Promise<number>((resolve) => {
302			const proc = spawn("pi", args, { cwd, shell: false, stdio: ["ignore", "pipe", "pipe"] });
303			let buffer = "";
304	
305			const processLine = (line: string) => {
306				if (!line.trim()) return;
307				let event: any;
308				try {
309					event = JSON.parse(line);
310				} catch {
311					return;
312				}
313				if (event.type === "message_end" && event.message) {
314					messages.push(event.message as Message);
315					onMessage?.(event.message as Message);
316				}
317				if (event.type === "tool_result_end" && event.message) {
318					messages.push(event.message as Message);
319					onMessage?.(event.message as Message);
320				}
321			};
322	
323			proc.stdout.on("data", (data: Buffer) => {
324				buffer += data.toString();
325				const lines = buffer.split("\n");
326				buffer = lines.pop() || "";
327				for (const line of lines) processLine(line);
328			});
329	
330			proc.stderr.on("data", (data: Buffer) => {
331				stderr += data.toString();
332			});
333	
334			proc.on("close", (code: number | null) => {
335				if (buffer.trim()) processLine(buffer);
336				resolve(code ?? 0);
337			});
338	
339			proc.on("error", () => resolve(1));
340	
341			if (signal) {
342				const killProc = () => {
343					wasAborted = true;
344					proc.kill("SIGTERM");
345					setTimeout(() => {
346						if (!proc.killed) proc.kill("SIGKILL");
347					}, 5000);
348				};
349				if (signal.aborted) killProc();
350				else signal.addEventListener("abort", killProc, { once: true });
351			}
352		});
353	
354		if (wasAborted) throw new Error("Thread was aborted");
355		return { exitCode, messages, stderr };
356	}
