471	function buildEpisode(messages: Message[]): string {
472		const parts: string[] = [];
473	
474		// Part 1: Tool call history — compact summary of what the thread did
475		const toolCalls: string[] = [];
476		for (const msg of messages) {
477			if (msg.role !== "assistant") continue;
478			for (const part of msg.content) {
479				if (part.type === "toolCall") {
480					const args = part.arguments as Record<string, unknown>;
481					switch (part.name) {
482						case "bash": {
483							const cmd = ((args.command as string) || "").replace(/\n/g, " ").replace(/\s+/g, " ").trim();
484							const preview = cmd.length > 120 ? cmd.slice(0, 120) + "..." : cmd;
485							toolCalls.push(`$ ${preview}`);
486							break;
487						}
488						case "read": {
489							const p = (args.file_path || args.path || "") as string;
490							const offset = args.offset as number | undefined;
491							const limit = args.limit as number | undefined;
492							let entry = `read ${p}`;
493							if (offset || limit) entry += `:${offset || 1}${limit ? `-${(offset || 1) + limit - 1}` : ""}`;
494							toolCalls.push(entry);
495							break;
496						}
497						case "write": {
498							const p = (args.file_path || args.path || "") as string;
499							const content = (args.content || "") as string;
500							const lines = content.split("\n").length;
501							toolCalls.push(`write ${p} (${lines} lines)`);
502							break;
503						}
504						case "edit": {
505							const p = (args.file_path || args.path || "") as string;
506							toolCalls.push(`edit ${p}`);
507							break;
508						}
509						default: {
510							const s = JSON.stringify(args);
511							toolCalls.push(`${part.name} ${s.length > 80 ? s.slice(0, 80) + "..." : s}`);
512						}
513					}
514				}
515			}
516		}
517	
518		if (toolCalls.length > 0) {
519			parts.push("TOOL CALLS:");
520			for (const tc of toolCalls) {
521				parts.push(`  ${tc}`);
522			}
523			parts.push("");
524		}
525	
526		// Part 2: Last assistant message — the thread's final response
527		const lastMessage = getFinalOutput(messages);
528		if (lastMessage.trim()) {
529			parts.push("THREAD RESPONSE:");
530			parts.push(lastMessage);
531		}
532	
533		return parts.join("\n") || "(no output)";
534	}
