186	function renderColumnsInRows(
187		items: ((colWidth: number) => string[])[],
188		width: number,
189		theme: any,
190	): string[] {
191		const sep = theme.fg("muted", "│");
192		const sepWidth = 3; // " │ "
193		const output: string[] = [];
194	
195		for (let rowStart = 0; rowStart < items.length; rowStart += MAX_COLUMNS) {
196			const rowItems = items.slice(rowStart, rowStart + MAX_COLUMNS);
197			const numCols = rowItems.length;
198			const colWidth = Math.floor((width - sepWidth * (numCols - 1)) / numCols);
199	
200			if (colWidth < 20) {
201				// Too narrow — stack vertically
202				for (const item of rowItems) {
203					output.push(...item(width));
204					output.push("");
205				}
206				continue;
207			}
208	
209			// Render each column
210			const columns: string[][] = rowItems.map((item) => item(colWidth));
211	
212			// Pad to same height with full-width spaces (so background fills)
213			const maxHeight = Math.max(...columns.map((c) => c.length));
214			for (const col of columns) {
215				while (col.length < maxHeight) col.push(" ".repeat(colWidth));
216			}
217	
218			// Zip lines
219			for (let row = 0; row < maxHeight; row++) {
220				const parts: string[] = [];
221				for (let c = 0; c < numCols; c++) {
222					const line = columns[c][row];
223					const padded = truncateToWidth(line, colWidth);
224					const pad = colWidth - visibleWidth(padded);
225					parts.push(padded + " ".repeat(Math.max(0, pad)));
226				}
227				output.push(parts.join(` ${sep} `));
228			}
229	
230			// Add spacing between rows of columns
231			if (rowStart + MAX_COLUMNS < items.length) {
232				output.push(" ".repeat(width));
233			}
234		}
235	
236		return output;
237	}
